!function(){"use strict";document.onreadystatechange=function(){var e;if("complete"===document.readyState){try{e=document.getElementById("redirect").textContent.replace(/\s/g,"")}catch(t){e=document.getElementById("redirect").innerHTML.replace(/\s/g,"")}if(e)return"form"===e?document.getElementById("form").submit():document.location.href=e;console.error("No redirection !")}}}();